mapper.select:
SELECT c.id, c.content, c.parent_id, c.author_id, c.reply_to_user_id, c.like_count, c.status, c.is_featured, c.created_at, u.nickname AS author_nickname, u.avatar AS author_avatar, ru.nickname AS reply_to_nickname, ru.avatar AS reply_to_avatar FROM comment c JOIN "user" u ON c.author_id = u.id AND u.deleted = 0 LEFT JOIN "user" ru ON c.reply_to_user_id = ru.id AND ru.deleted = 0 WHERE c.parent_id IN
#{pid}
AND c.deleted = 0 AND c.status = 1 ORDER BY c.created_at ASC
